CREATE TABLE jobs(id TEXT PRIMARY KEY, run_id TEXT NOT NULL REFERENCES runs(id) ON DELETE CASCADE, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, status TEXT NOT NULL, priority INTEGER NOT NULL DEFAULT 0, payload TEXT NOT NULL, checkpoint TEXT NOT NULL, cancellation_requested INTEGER NOT NULL DEFAULT 0, attempts INTEGER NOT NULL DEFAULT 0, locked_by TEXT, locked_at TEXT, error TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX ix_jobs_status_priority ON jobs(status,priority,created_at);
CREATE TABLE run_steps(id TEXT PRIMARY KEY, run_id TEXT NOT NULL REFERENCES runs(id) ON DELETE CASCADE, pipeline_node_id TEXT NOT NULL, status TEXT NOT NULL, attempt INTEGER NOT NULL DEFAULT 0, input TEXT NOT NULL, output TEXT, error TEXT, started_at TEXT, completed_at TEXT, UNIQUE(run_id,pipeline_node_id));
CREATE TABLE pricing_rules(id TEXT PRIMARY KEY, provider TEXT NOT NULL, model_pattern TEXT NOT NULL, input_micros_per_million INTEGER NOT NULL, output_micros_per_million INTEGER NOT NULL, cache_micros_per_million INTEGER NOT NULL DEFAULT 0, currency TEXT NOT NULL, effective_at TEXT NOT NULL, markup REAL NOT NULL, source TEXT NOT NULL, active INTEGER NOT NULL DEFAULT 0, created_by TEXT NOT NULL REFERENCES users(id), created_at TEXT NOT NULL, UNIQUE(provider,model_pattern,effective_at));
CREATE TABLE quota_policies(id TEXT PRIMARY KEY, user_id TEXT REFERENCES users(id) ON DELETE CASCADE, monthly_micros INTEGER NOT NULL, per_run_micros INTEGER NOT NULL, max_parallel_runs INTEGER NOT NULL, effective_at TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE payment_transactions(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), provider TEXT NOT NULL, checkout_session_id TEXT UNIQUE, payment_intent_id TEXT, status TEXT NOT NULL, amount_micros INTEGER NOT NULL, credits_micros INTEGER NOT NULL, currency TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE oauth_identities(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE, provider TEXT NOT NULL, subject TEXT NOT NULL, email TEXT, created_at TEXT NOT NULL, UNIQUE(provider,subject));
CREATE TABLE auth_challenges(id TEXT PRIMARY KEY, user_id TEXT REFERENCES users(id) ON DELETE CASCADE, challenge_type TEXT NOT NULL, token_hash TEXT NOT NULL UNIQUE, payload TEXT NOT NULL, expires_at TEXT NOT NULL, consumed_at TEXT, created_at TEXT NOT NULL);
CREATE TABLE invitations(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, email TEXT NOT NULL, role TEXT NOT NULL, token_hash TEXT NOT NULL UNIQUE, invited_by TEXT NOT NULL REFERENCES users(id), status TEXT NOT NULL, expires_at TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX ix_invitations_email_status ON invitations(email,status);
CREATE TABLE merge_proposals(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, source_branch_id TEXT NOT NULL REFERENCES branches(id), target_branch_id TEXT NOT NULL REFERENCES branches(id), status TEXT NOT NULL, diff TEXT NOT NULL, conflicts TEXT NOT NULL, created_by TEXT NOT NULL REFERENCES users(id), reviewed_by TEXT REFERENCES users(id), created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE artifacts(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, run_id TEXT REFERENCES runs(id), owner_id TEXT NOT NULL REFERENCES users(id), filename TEXT NOT NULL, media_type TEXT NOT NULL, size_bytes INTEGER NOT NULL, sha256 TEXT NOT NULL, storage_key TEXT NOT NULL UNIQUE, metadata TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX ix_artifacts_project ON artifacts(project_id,created_at);
CREATE TABLE embeddings(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, object_type TEXT NOT NULL, object_id TEXT NOT NULL, model TEXT NOT NULL, dimensions INTEGER NOT NULL, vector TEXT NOT NULL, search_text TEXT NOT NULL, created_at TEXT NOT NULL, UNIQUE(object_type,object_id,model));
CREATE TABLE plugin_packages(id TEXT PRIMARY KEY, plugin_id TEXT NOT NULL, version TEXT NOT NULL, manifest TEXT NOT NULL, checksum TEXT NOT NULL, source TEXT NOT NULL, enabled INTEGER NOT NULL DEFAULT 0, approval_status TEXT NOT NULL, installed_by TEXT NOT NULL REFERENCES users(id), installed_at TEXT NOT NULL, UNIQUE(plugin_id,version));
CREATE TABLE plugin_audit(id TEXT PRIMARY KEY, package_id TEXT REFERENCES plugin_packages(id), actor_id TEXT NOT NULL REFERENCES users(id), operation TEXT NOT NULL, detail TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE benchmark_tasks(id TEXT PRIMARY KEY, name TEXT NOT NULL, fixture TEXT NOT NULL, metrics_schema TEXT NOT NULL, created_at TEXT NOT NULL);
